en["getinvolved"]["s001"]=en["getinvolved"]["s001"]||"Get Involved";
en["getinvolved"]["s002"]=en["getinvolved"]["s002"]||"Help bring AI medical imaging to the clinics that need it most. ScanGuru Ambassadors are volunteers who support our Heal for All mission through outreach, education, and community — in their own regions and languages.";
en["getinvolved"]["s003"]=en["getinvolved"]["s003"]||"Why it matters";
en["getinvolved"]["s004"]=en["getinvolved"]["s004"]||"Through our Heal for All program, ScanGuru provides free access to verified low-income-country clinics, children's cancer hospitals, and charity hospitals. Reaching those communities — in the right places, and in the right languages — is something we can't do alone.";
en["getinvolved"]["s005"]=en["getinvolved"]["s005"]||"How you can help";
en["getinvolved"]["s006"]=en["getinvolved"]["s006"]||"Pick the way that fits you. Every role is non-clinical and community-focused.";
en["getinvolved"]["s007"]=en["getinvolved"]["s007"]||"Community outreach";
en["getinvolved"]["s008"]=en["getinvolved"]["s008"]||"Connect us with clinics, NGOs, and hospitals in underserved regions that could qualify for free Heal for All access.";
en["getinvolved"]["s009"]=en["getinvolved"]["s009"]||"Education & awareness";
en["getinvolved"]["s010"]=en["getinvolved"]["s010"]||"Support awareness sessions and share how responsible AI imaging works — with students, community groups, and local healthcare networks.";
en["getinvolved"]["s011"]=en["getinvolved"]["s011"]||"Language & localization";
en["getinvolved"]["s012"]=en["getinvolved"]["s012"]||"Help us reach communities in their own language by reviewing our public and educational materials — marketing and community content, never clinical reports.";
en["getinvolved"]["s013"]=en["getinvolved"]["s013"]||"Academic & research network";
en["getinvolved"]["s014"]=en["getinvolved"]["s014"]||"Introduce us to universities and researchers interested in our research-use pilots.";
en["getinvolved"]["s015"]=en["getinvolved"]["s015"]||"What the role is not";
en["getinvolved"]["s016"]=en["getinvolved"]["s016"]||"To keep patients safe and our claims honest, ambassadors never:";
en["getinvolved"]["s017"]=en["getinvolved"]["s017"]||"Interpret or validate scans";
en["getinvolved"]["s018"]=en["getinvolved"]["s018"]||"Reading images and confirming findings is the work of qualified clinicians — not volunteers.";
en["getinvolved"]["s019"]=en["getinvolved"]["s019"]||"Make medical or performance claims";
en["getinvolved"]["s020"]=en["getinvolved"]["s020"]||"Ambassadors don't speak to accuracy, diagnosis, or regulatory status on ScanGuru's behalf.";
en["getinvolved"]["s021"]=en["getinvolved"]["s021"]||"Handle patient data";
en["getinvolved"]["s022"]=en["getinvolved"]["s022"]||"No access to patient images, reports, or any protected health information.";
en["getinvolved"]["s023"]=en["getinvolved"]["s023"]||"Who it's for";
en["getinvolved"]["s024"]=en["getinvolved"]["s024"]||"Students, healthcare advocates, community organizers, multilingual volunteers — anyone who wants to help widen access to medical imaging. No technical background required.";
en["getinvolved"]["s025"]=en["getinvolved"]["s025"]||"Join the mission";
en["getinvolved"]["s026"]=en["getinvolved"]["s026"]||"Tell us a bit about you and how you'd like to help, and we'll be in touch.";
en["getinvolved"]["s027"]=en["getinvolved"]["s027"]||"Get in touch";
