en["heal"]["apply_eyebrow"]=en["heal"]["apply_eyebrow"]||"How to apply";
en["heal"]["apply_title"]=en["heal"]["apply_title"]||"Three steps, as little friction as we could manage";
en["heal"]["applycta_h"]=en["heal"]["applycta_h"]||"Ready to bring ScanGuru to your clinic?";
en["heal"]["applycta_p"]=en["heal"]["applycta_p"]||"Tell us your modality and use case — we'll handle the rest. No cost, no card, no catch.";
en["heal"]["cta_apply"]=en["heal"]["cta_apply"]||"Apply for free access";
en["heal"]["cta_apply2"]=en["heal"]["cta_apply2"]||"Start your application";
en["heal"]["cta_fund"]=en["heal"]["cta_fund"]||"For funders & grant partners";
en["heal"]["cta_partner"]=en["heal"]["cta_partner"]||"Talk to us about sponsoring";
en["heal"]["e1_h"]=en["heal"]["e1_h"]||"Low-income-country institutions";
en["heal"]["e1_p"]=en["heal"]["e1_p"]||"Clinics, hospitals, and universities in low- or lower-middle-income countries.";
en["heal"]["e2_h"]=en["heal"]["e2_h"]||"Rural & underserved clinics";
en["heal"]["e2_p"]=en["heal"]["e2_p"]||"Facilities serving communities far from specialist radiology.";
en["heal"]["e3_h"]=en["heal"]["e3_h"]||"Children's & elderly cancer hospitals";
en["heal"]["e3_p"]=en["heal"]["e3_p"]||"Paediatric and geriatric oncology, where early reads matter most.";
en["heal"]["e4_h"]=en["heal"]["e4_h"]||"Registered charities & non-profits";
en["heal"]["e4_p"]=en["heal"]["e4_p"]||"Charitable healthcare providers and humanitarian organisations.";
en["heal"]["eyebrow"]=en["heal"]["eyebrow"]||"Heal for All · Our standing commitment";
en["heal"]["f1_h"]=en["heal"]["f1_h"]||"100 scans every month";
en["heal"]["f1_p"]=en["heal"]["f1_p"]||"Renewing monthly — enough for a small clinic to run real caseloads, not a demo.";
en["heal"]["f2_h"]=en["heal"]["f2_h"]||"The full platform";
en["heal"]["f2_p"]=en["heal"]["f2_p"]||"Every supported modality, explainable AI reads, and the technical appendix. Nothing held back.";
en["heal"]["f3_h"]=en["heal"]["f3_h"]||"Reports in 83 languages";
en["heal"]["f3_p"]=en["heal"]["f3_p"]||"Dual-language reports so your patients can read their own results.";
en["heal"]["f4_h"]=en["heal"]["f4_h"]||"No card, no licence fee";
en["heal"]["f4_p"]=en["heal"]["f4_p"]||"For verified institutions this is lifetime access — not a 30-day trial.";
en["heal"]["f5_h"]=en["heal"]["f5_h"]||"Nothing to install";
en["heal"]["f5_p"]=en["heal"]["f5_p"]||"Runs in a browser, so there's no expensive local infrastructure to maintain.";
en["heal"]["f6_h"]=en["heal"]["f6_h"]||"Part of the mission";
en["heal"]["f6_p"]=en["heal"]["f6_p"]||"The same equitable-access commitment we extend to every clinic we serve.";
en["heal"]["free_eyebrow"]=en["heal"]["free_eyebrow"]||"What \"free\" actually means";
en["heal"]["free_sub"]=en["heal"]["free_sub"]||"No stripped-down tier, no countdown timer. Verified institutions get real capacity and the full feature set.";
en["heal"]["free_title"]=en["heal"]["free_title"]||"Not a trial. The whole platform, for good.";
en["heal"]["fund_eyebrow"]=en["heal"]["fund_eyebrow"]||"For funders & grant partners";
en["heal"]["fund_sub"]=en["heal"]["fund_sub"]||"Most digital-health tools ask funders to underwrite a platform. We ask you to underwrite a clinic — a specific, named facility — and we report back exactly how many scans it ran.";
en["heal"]["fund_title"]=en["heal"]["fund_title"]||"Sponsor a clinic — fund a specific, reportable outcome";
en["heal"]["fundcta_h"]=en["heal"]["fundcta_h"]||"Fund a clinic. Get an honest report back.";
en["heal"]["fundcta_p"]=en["heal"]["fundcta_p"]||"Grant councils, foundations, companies, and individual donors — let's define a unit you can measure.";
en["heal"]["hero_lead"]=en["heal"]["hero_lead"]||"ScanGuru is free — for life — for verified low-income-country institutions, rural clinics, and children's and elderly cancer hospitals. The full platform, dual-language reports in 83 languages, no card required.";
en["heal"]["hero_note"]=en["heal"]["hero_note"]||"AI-assisted predictions require radiologist verification. ScanGuru is clinician-reviewed decision support — a qualified clinician confirms every finding. Not FDA-cleared or CE-marked.";
en["heal"]["hero_title"]=en["heal"]["hero_title"]||"Free for the clinics the world overlooks.";
en["heal"]["honesty_h"]=en["heal"]["honesty_h"]||"We will never show you a number our system didn't record.";
en["heal"]["honesty_p"]=en["heal"]["honesty_p"]||"Our usage counter both enforces the free tier and reports your impact, so there's nothing to inflate. We don't publish accuracy figures we can't yet stand behind — which is exactly why we partner with universities to validate independently. ScanGuru is research use and not FDA-cleared or CE-marked.";
en["heal"]["promise_h"]=en["heal"]["promise_h"]||"If you reach your monthly limit, we don't cut you off mid-care.";
en["heal"]["promise_p"]=en["heal"]["promise_p"]||"We get in touch — because a clinic hitting its limit usually means it's helping more people, and that's exactly what we built this for.";
en["heal"]["s1_h"]=en["heal"]["s1_h"]||"Tell us about your institution";
en["heal"]["s1_p"]=en["heal"]["s1_p"]||"A short form: name, country, type, and what you'd use ScanGuru for.";
en["heal"]["s2_h"]=en["heal"]["s2_h"]||"We verify";
en["heal"]["s2_p"]=en["heal"]["s2_p"]||"A quick human review, usually within a few days. We may ask for a registration number or a link.";
en["heal"]["s3_h"]=en["heal"]["s3_h"]||"You're in";
en["heal"]["s3_p"]=en["heal"]["s3_p"]||"Once verified, your free access is switched on — for good.";
en["heal"]["th1"]=en["heal"]["th1"]||"Tier";
en["heal"]["th2"]=en["heal"]["th2"]||"What it funds";
en["heal"]["th3"]=en["heal"]["th3"]||"What the sponsor gets back";
en["heal"]["tiers_h"]=en["heal"]["tiers_h"]||"Sponsorship tiers";
en["heal"]["tiers_sub"]=en["heal"]["tiers_sub"]||"Structure shown; figures set against real inference and support cost.";
en["heal"]["toc1_l"]=en["heal"]["toc1_l"]||"Problem";
en["heal"]["toc1_p"]=en["heal"]["toc1_p"]||"Billions live where there is no radiologist. Scans go unread or wait weeks.";
en["heal"]["toc2_l"]=en["heal"]["toc2_l"]||"Intervention";
en["heal"]["toc2_p"]=en["heal"]["toc2_p"]||"An explainable AI second read with a dual-language report, in a browser, free.";
en["heal"]["toc3_l"]=en["heal"]["toc3_l"]||"Outcome";
en["heal"]["toc3_p"]=en["heal"]["toc3_p"]||"Faster triage, fewer missed findings, results patients can actually read.";
en["heal"]["toc4_l"]=en["heal"]["toc4_l"]||"Evidence";
en["heal"]["toc4_p"]=en["heal"]["toc4_p"]||"Every clinic's usage is counted and reported. University partners validate independently.";
en["heal"]["tr1a"]=en["heal"]["tr1a"]||"Sponsor a clinic";
en["heal"]["tr1b"]=en["heal"]["tr1b"]||"1 verified clinic, 1 year";
en["heal"]["tr1c"]=en["heal"]["tr1c"]||"Named clinic + annual usage report (scans run, modalities, country)";
en["heal"]["tr2a"]=en["heal"]["tr2a"]||"Sponsor a cohort";
en["heal"]["tr2b"]=en["heal"]["tr2b"]||"5–10 clinics in a region";
en["heal"]["tr2c"]=en["heal"]["tr2c"]||"Regional impact summary + aggregate usage";
en["heal"]["tr3a"]=en["heal"]["tr3a"]||"Country programme";
en["heal"]["tr3b"]=en["heal"]["tr3b"]||"All eligible facilities in one country";
en["heal"]["tr3c"]=en["heal"]["tr3c"]||"Country-level rollout + longitudinal data";
en["heal"]["tr4a"]=en["heal"]["tr4a"]||"Research partnership";
en["heal"]["tr4b"]=en["heal"]["tr4b"]||"A university validation study";
en["heal"]["tr4c"]=en["heal"]["tr4c"]||"Co-branded validation results, publishable";
en["heal"]["unit_label"]=en["heal"]["unit_label"]||"The fundable unit:";
en["heal"]["unit_text"]=en["heal"]["unit_text"]||"one sponsored clinic = one year of free ScanGuru access for a verified underserved facility = a defined monthly scan allocation, reported back with real usage data drawn straight from our counter.";
en["heal"]["who_eyebrow"]=en["heal"]["who_eyebrow"]||"Who qualifies";
en["heal"]["who_sub"]=en["heal"]["who_sub"]||"Four straightforward categories. Not sure which fits? Apply anyway — we'd rather say yes than make you guess.";
en["heal"]["who_title"]=en["heal"]["who_title"]||"Built for the institutions that need it most";
